[asy]
unitsize(0.5 cm);

pair A, B, C, O;

A = (-2,5);
B = (1,3);
O = (0,0);
C = extension(O, reflect(O,B)*(A), A, B);

draw(O--A,Arrow(6));
draw(O--B,Arrow(6));
